VALUES
  ('promotion-6f0ba476-moex-00025', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '下列那些事項會影響保留盈餘？①公司聘用員工，每月發放薪資並認列薪資費用  ②公司現', '["公司宣告並發放股票股利", "公司進行股票分割", "僅", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00026', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', 'X4年12月1日爾柳公司決定處分其燈泡部門，該部門X4年之稅前營業淨利為$150,000，期 末資產為$3,000,000，負債為$2,000,000，X4年底燈泡部門的估計公允價值為$675,000，估計 出售成本為Y元。公司估計該部門於X5年1月1日至3月31日有營業損失$50,000（稅前）， 3月31日完成出售時，產生出售損失$125,000（稅前）。若所得稅率為20%，X4年爾柳公司 綜合損益表中列示停業單位損失金額為$200,000，則Y為多少？', '["$75,000", "$100,000", "$112,500", "$120,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00027', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '爾戚公司 X5 年初流通在外普通股股數為 510,000 股，3 月 1 日及 7 月 1 日分別發行新股 30,000股、買回庫藏股55,000股。10月1日發生兩項交易，包含⑴進行1：2股票分割（即', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00028', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '股分割成 2 股）、⑵發行 6%、面額$1,000 可轉換公司債 500 張，每張可轉換成普通股 90 股，公司債具稀釋作用，但直至年底無人轉換。計算爾戚公司 X5 年度基本每股盈餘之加權 平均流通在外股數為多少股？', '["628,750", "640,000", "1,015,000", "1,026,250"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00029', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '爾巴公司於X5年1月1日簽訂一項工程興建合約，該合約之承諾為隨時間逐步滿足之單一 履約義務。合約總價款為$3,000,000，X5年已發生工程成本$1,800,000，預期很有可能回收之 成本為$1,560,000。X5年已開立帳單與已收款金額分別為$900,000、$700,000。爾巴公司對工 程完成程度無法合理衡量，試問爾巴公司X5年應認列之工程（損）益為何？', '["$0", "$(240,000)", "$(660,000)", "$(860,000)"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00030', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'essay', '租稅行政罰與租稅刑事罰二者於適用條件及救濟程序上有何不同？另
請依現行稅捐稽徵法的規定，分別舉例說明二者被處罰的情狀及處罰的
項目。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00031', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'essay', '甲公司為一家剛成立的公司，屬加值型及非加值型營業稅法第四章第一
節規定計算稅額的營業人，公司主要業務為進出口貿易，其總公司設立
在臺北市，預計會在臺中市及高雄市分別設立分公司。
請依我國營業稅法說明其營業稅之報繳期間及總分支機構如何申報
之規定。（15分）
請依法說明不可扣抵的進項稅額情形。（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00032', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '臺灣甲公司向日本乙公司購買機器二台，乙公司總機構在中華民國境外，且在我國境內無固定營 業場所及營業代理人，乙公司指派員工A來臺指導機台安裝、試車及操作等工作，A於114年6月 1日來臺，同年9月1日返日，乙公司支付A薪資80萬元，下列何者正確？', '["免納所得稅", "甲公司應辦理薪資所得扣繳申報", "A應於離臺前就獲取之80萬元薪資向國稅局辦理申報納稅", "乙公司委託甲公司向國稅局辦理申報納稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00033', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依現行綜合所得稅申報基本生活費差額之規定，下列何者正確？①基本生活費總額計算時，必須', '["比較扣除總額時，應包含免稅額、一般扣 除額（標準或列舉擇一）及特別扣除額，但不包括薪資特別扣除額與財產交易損失", "若比較後 差額為負值，應仍列報0元差額於申報書內", "差額扣除僅在基本生活費總額大於免稅額及相關 扣除額合計時，才得減除差額", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00034', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '趙先生為美國籍，114年在臺停留未滿183日，屬非居住者。當年度曾贈與子女一筆臺灣不動產 （公告土地現值200萬元、房屋評定標準價格150萬元），並另以在臺存款贈與現金100萬元。 依遺產及贈與稅法規定，下列何者錯誤？', '["非居住者贈與境內財產，應就其價值申報贈與稅", "贈與不動產時，應以公告土地現值與房屋評定標準價格合計作為贈與價值", "贈與總額450萬元扣除免稅額244萬元後，應稅淨額為206萬元，適用10%稅率計算贈與稅", "居住者不得適用年度贈與稅免稅額244萬元，應就全部450萬元課稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
